 1	import * as React from 'react';
 2	import classnames from 'classnames';
 3	
 4	import { pluralize, Tooltip } from '@patternfly/react-core';
 5	import { GlobeAmericasIcon } from '@patternfly/react-icons';
 6	
 7	import { isValid, timestampFor, utcDateTimeFormatter } from './utils/datetime';
 8	
 9	export type TimestampProps = {
10	  className?: string;
11	  hideIcon?: boolean;
12	  omitSuffix?: boolean;
13	  timestamp: number | string;
14	};
15	
16	const Timestamp: React.FC<TimestampProps> = ({
17	  className,
18	  hideIcon = false,
19	  omitSuffix,
20	  timestamp,
21	}) => {
22	  // Check for null. If props.timestamp is null, it returns incorrect date and time of Wed Dec 31 1969 19:00:00 GMT-0500 (Eastern Standard Time)
23	  if (!timestamp || !isValid(new Date(timestamp))) {
24	    return <div className="co-timestamp">-</div>;
25	  }
26	
27	  const mdate = new Date(timestamp);
28	
29	  const newTimestamp = timestampFor(mdate, new Date(Date.now()), omitSuffix);
30	
31	  const timeStamp = omitSuffix
32	    ? pluralize(newTimestamp['value'], newTimestamp['time'])
33	    : newTimestamp;
34	
35	  return (
36	    <div className={classnames('co-timestamp', 'co-icon-and-text', className)}>
37	      {!hideIcon && <GlobeAmericasIcon className="co-icon-and-text__icon" />}
38	      <Tooltip
39	        content={[
40	          <span className="co-nowrap" key="co-timestamp">
41	            {utcDateTimeFormatter.format(mdate)}
42	          </span>,
43	        ]}
44	      >
45	        <span data-test="timestamp">{timeStamp}</span>
46	      </Tooltip>
47	    </div>
48	  );
49	};
50	
51	export default Timestamp;

